syntax = "proto3";

package ar2es2Proto;

option go_package = "github.com/IGS-ARCADE-DIVISION-RD2/uk_872_eyestrike2_proto/go/ar2es2Proto";

// ingame
message Column {
  repeated int32 Col = 1;
}

message CColumn {
  repeated CSymbol Col = 1;
}

message CSymbol {
  int32 Symbol = 1;                   // symbol
  int32 JPState = 2;                  // jp state(0:none, 1:mini, 2:minor, 3:major, 4:mega, 5:grand)
  double Number = 3;                  // number(cash分數)
}

message AwardData {
  int32 AwardType = 1;               // 獎項類型(1:線獎, 2:cash獎)
  int32 Symbol = 2;                   // 中獎symbol
  int32 Count = 3;                    // 中獎數量
  int32 Line = 4;                     // 中獎線數
  double Win = 5;                     // 中獎金額(已乘倍)
  double Multiplier = 6;              // 乘倍
  double JackpotWin = 7;              // 快測用(JP贏分)
}

message FeatureResult {
  int32 Type = 1;                     // WheelFeature 類型(0:FG, 1:Multi, 2:Upgrade, 3:Transfer, 4:Grand, -1:None)
  int32 SlotIndex = 2;                // 轉盤上的格子 index（0~9），未觸發為 -1
  int32 Count = 3;                    // 加成數量
  repeated int32 Positions = 4;       // 貼放位置 (col*RowNum + row)
  repeated int32 Multipliers = 5;     // 每格的乘倍數值（僅 Multi 時有效）
  double Win = 6;                     // 贏分（僅 Grand 時有效）
}

message ScAccuUpgradeInfo {
  bool Upgrade = 1;                   // 是否升級（stage 有變化）
  int32 Stage = 2;                    // 最終 stage
  int32 Count = 3;                    // 最終累積數量
}

message TransformInfo {
  int32 Pos = 1;                      // 格子位置 (col*RowNum + row)
  int32 Symbol = 2;                   // 轉換/升級後的 symbol
  int32 JPState = 3;                  // JP 種類 (0=none)
  double Number = 4;                  // 分數
}

message GridInfo {
  int32 Mark = 1;                     // bitmask: 0x01=Multi, 0x02=Upgrade, 0x04=Transfer
  int32 Multiplier = 2;               // 乘倍數值
}

message GridColumn {
  repeated GridInfo Col = 1;
}

message PlateInfo {
  repeated CColumn PlateSymbol = 1;   // 盤面
  repeated AwardData AwardDataVec = 2; // 獎項紀錄
  double Win = 3;                     // 本次贏分
  repeated IntAry FeaturePosQueue = 4; // 特殊 symbol 位置
}

message IntAry {
  repeated int32 Data = 1;
}

message RoundInfo {
  int32 AwardTypeFlag = 5;
  double RoundWin = 6;                  // 這一個round贏分
  int32 ReelWeightResult = 7;           // 實際轉輪帶編號
  bool MaxFlag = 8;                     // 是否達到最大獎勵

  int32 CurrFeverGameType = 15;   // 目前免費遊戲類型(0:none, 1:free game, 2: respin game, 3: free respin game)
  int32 NextFeverGameType = 16;   // 下一手免費遊戲類型
  int32 FreeRemainRound = 17;     // 剩餘免費遊戲局數
  int32 FreeNowRound = 18;        // 現在免費遊戲局數
  int32 FreeTotalRound = 21;            // 免費遊戲總局數

  int32 MysteryEventKind = 22;  // mystery event種類
  int32 NearMissKind = 23;      // 聽牌種類
  int32 NearMissStartCol = 24;  // 開始聽牌輪


  int32 PreScAccuStage = 30;    // 本手開始前的 SC_ACCU stage
  int32 PreScAccuCount = 31;    // 本手開始前的 SC_ACCU 累積數量
  int32 ScAccuStage = 32;       // 本手結束後的 SC_ACCU stage
  int32 ScAccuCount = 33;       // 本手結束後的 SC_ACCU 累積數量
  ScAccuUpgradeInfo ScAccuUpgrade = 34; // SC 累積升級紀錄

  int32 FreeGameExtraSpins = 35;  // free game額外轉數
  repeated int32 RespinLockedPos = 38;  // respin game 鎖住位置

  repeated FeatureResult WheelFeatures = 50;  // Wheel Feature 觸發列表（依序表演）
  int32 WheelCount = 51;                      // 轉輪次數
  repeated GridColumn PreGridFeature = 52;    // 本手開始時的 GridFeature（recovery 用）
  repeated TransformInfo TransferResult = 53; // Transfer 轉換紀錄
  repeated TransformInfo UpgradeResult = 54;  // Upgrade 升級紀錄
  repeated PlateInfo PlateQueue = 55;         // 盤面資料（初始 + respin 後等）
}

message SpinAck {
  repeated RoundInfo RoundQueue = 1;
  double FreeTotalWin = 2;
  double TotalWin = 3;
  double Bet = 4;
  int32 ScAccuStage = 6;       // 最終 SC_ACCU stage
  int32 ScAccuCount = 7;       // 最終 SC_ACCU 累積數量
  int32 BetType = 8;
}

message StateInfo {
  int32 ScAccuStage = 2;       // SC_ACCU stage
  int32 ScAccuCount = 3;       // SC_ACCU 累積數量
}

message GameInfoData {
  bool ShowExtra = 1;
  repeated double Mul = 2;
  repeated double JPOdds = 3;        // JP odds
  repeated IntAry WheelData = 4;     // wheel data
  int32 ScAccuStage = 6;             // SC_ACCU stage
  int32 ScAccuCount = 7;             // SC_ACCU 累積數量
  double MaxBet = 8;                
  repeated double BuyMul = 9;      
}

message BuyReq {
  double BaseBet = 1;
  int32 BuyType = 2;
}

