21	 */
22	export const FEATURE_WHEEL_EVENT = {
23	    /**
24	     * @ch 初始化
25	     * @param gameView 遊戲視窗
26	     */
27	    INIT: 'FEATURE_WHEEL_INIT',
28	
29	    /**
30	     * @ch 設置 12 格輪盤資料（server 給）
31	     * @param segments SegmentDescriptor[]（每格 type；None 格不顯示）
32	     */
33	    SET_WHEEL_DATA: 'FEATURE_WHEEL_SET_WHEEL_DATA',
34	
35	    /**
36	     * @ch 轉動並落在指定格
37	     * @param landIndex 落點格索引 (0~11)
38	     * @param callback (選填) (result: SpinResult) => void
39	     */
40	    PLAY_SPIN: 'FEATURE_WHEEL_PLAY_SPIN',
41	
42	    /**@ch 顯示 UI*/
43	    SHOW_UI: 'FEATURE_WHEEL_SHOW_UI',
44	
45	    /**@ch 隱藏 UI*/
46	    HIDE_UI: 'FEATURE_WHEEL_HIDE_UI',
47	
48	    /**
49	     * @ch 手動恢復 Idle 緩轉
50	     * PlaySpin 後輪盤停住不自動恢復；待盤面其他表演結束，由呼叫端 dispatch 此事件才繼續緩轉
51	     */
52	    RESUME_IDLE: 'FEATURE_WHEEL_RESUME_IDLE',
53	
54	    /**
55	     * @ch 隱藏結果展示牌（暫代落點演出的退場）
56	     * PlayLandAnnounce 秀出展示牌後即 resolve、不自動收；由呼叫端在結果演出結束後 dispatch 此事件退場
57	     */
58	    HIDE_RESULT: 'FEATURE_WHEEL_HIDE_RESULT',
59	};
60	
61	/**
62	 * @ch Feature Wheel 輪盤 UI 元件
63	 * 單一職責：顯示 12 格、平時 Idle 緩轉、依 server 資料換 icon、轉動落在指定格、播落點演出、把選中功能拋給外部
64	 * 不碰盤面標記/重轉/改符號（呼叫端責任）
65	 */
66	@ccclass('FeatureWheelManager')
67	export class FeatureWheelManager extends Component {
68	    //#region 屬性
69	    /**@ch 根節點（顯示/隱藏）*/
70	    @property({ type: Node, displayName: '根節點' })
71	    private m_rootNode: Node = null;
72	
73	    /**@ch 輪盤旋轉節點（轉動的是這個，頂端指針固定不動）*/
74	    @property({ type: Node, displayName: '輪盤旋轉節點' })
75	    private m_wheelNode: Node = null;
76	
77	    /**@ch 12 格 icon 的 SpriteChange（順序對應格 0~11）*/
78	    @property({ type: [SpriteChange], displayName: '12 格 icon SpriteChange' })
79	    private m_segmentSpriteChanges: SpriteChange[] = [];
80	
81	    /**@ch 12 格乘倍數值 Label（非乘倍格留空字串；順序對應格 0~11）*/
82	    @property({ type: [Label], displayName: '12 格乘倍數值 Label' })
83	    private m_segmentValueLabels: Label[] = [];
84	
85	    /**@ch 12 格落點演出節點（順序對應格 0~11；現僅供 DevAssertConfig 數量檢查，落點演出已改用結果展示牌）*/
86	    @property({ type: [Node], displayName: '12 格落點演出節點' })
87	    private m_segmentNodes: Node[] = [];
88	
89	    /**@ch 結果展示牌根節點（暫代落點演出：顯示落點 feature 符號；退場由 HIDE_RESULT 事件觸發）*/
90	    @property({ type: Node, displayName: '結果展示牌根節點' })
91	    private m_resultNode: Node = null;
92	
93	    /**@ch 結果展示牌符號 SpriteChange（5 張圖索引對齊 TYPE_ICON_CONFIG，與 12 格 icon 同套索引）*/
94	    @property({ type: SpriteChange, displayName: '結果展示牌符號 SpriteChange' })
95	    private m_resultSpriteChange: SpriteChange = null;
96	
97	    /**@ch 結果展示牌背景 SpriteChange（背景隨落點 type 切換；5 張圖索引同 m_resultSpriteChange）*/
98	    @property({ type: SpriteChange, displayName: '結果展示牌背景 SpriteChange' })
99	    private m_resultBgSpriteChange: SpriteChange = null;
100	
101	    /**@ch 轉動方向：勾選=順時針，取消=逆時針（預設順時針）*/
102	    @property({ displayName: '順時針轉動' })
103	    private m_clockwise: boolean = true;
104	
105	    /**@ch Idle 緩轉一圈秒數（越大越慢；≤0 視為不緩轉）；方向跟隨「順時針轉動」*/
106	    @property({ displayName: 'Idle 一圈秒數' })
107	    private m_idleSecondsPerRev: number = 60;
108	    //#endregion 屬性
109	
110	    //#region 常數
111	    /**@ch 轉動時間（秒）；拉長以降低峰值角速度，減輕 12 格重複圖樣的車輪錯覺（視覺反向）*/
112	    private static readonly ROTATE_TIME = 3;//2.5;
113	    //#endregion 常數
114	
115	    //#region 變數
116	    /**@ch 遊戲視窗*/
117	    private m_gameView: GameView = null;
118	    /**@ch 是否初始化*/
119	    private m_isInit = false;
120	    /**@ch 是否轉動中（轉動中/閒置兩互斥態）*/
121	    private m_isSpinning = false;
122	    /**@ch 是否處於 Idle 緩轉態（SHOW_UI/RESUME_IDLE 開、HIDE_UI/PlaySpin 關；轉動中由 m_isSpinning 暫停，轉完不自動恢復）*/
123	    private m_isIdle = false;
124	    /**@ch 是否已註冊事件*/
125	    private m_isEventRegistered = false;
126	    /**@ch 當前 12 格資料*/
127	    private m_segments: SegmentDescriptor[] = [];
128	
129	    /**@ch 事件列表*/
130	    private readonly EVENT_LIST: string[] = [
131	        FEATURE_WHEEL_EVENT.INIT,
132	        FEATURE_WHEEL_EVENT.SET_WHEEL_DATA,
133	        FEATURE_WHEEL_EVENT.PLAY_SPIN,
134	        FEATURE_WHEEL_EVENT.SHOW_UI,
135	        FEATURE_WHEEL_EVENT.HIDE_UI,
136	        FEATURE_WHEEL_EVENT.RESUME_IDLE,
137	        FEATURE_WHEEL_EVENT.HIDE_RESULT,
138	    ];
139	    //#endregion 變數
140	
141	    //#region 生命週期
142	    onLoad() {
143	        this.RegisterEvent();
144	        this.DevAssertConfig();
145	        this.RegisterTestKeyCodes();
146	    }
147	
148	    onDestroy() {
149	        this.UnregisterEvent();
150	        this.UnregisterTestKeyCodes();
151	    }
152	
153	    /**
154	     * @ch 每幀 Idle 緩轉：僅在 Idle 態且非轉動中執行（兩旋轉路徑互斥，不同幀寫 m_wheelNode）
155	     * 方向跟隨 m_clockwise（順時針 = z 遞減，與 ComputeTargetAngle 一致）
156	     */
157	    update(dt: number) {
158	        if (!this.m_isIdle || this.m_isSpinning) {
159	            return;
160	        }
161	        if (this.m_idleSecondsPerRev <= 0) {
162	            return;
163	        }
164	        if (!this.m_wheelNode || !this.m_wheelNode.isValid) {
165	            return;
166	        }
167	        const dir = this.m_clockwise ? -1 : 1;
168	        const deltaAngle = dir * (360 / this.m_idleSecondsPerRev) * dt;
169	        // 正規化防 BC-8 連續累積漂移（與 RotateToIndex 收尾一致），spin 起點讀 currentAngle 仍正確
170	        const next = NormalizeAngle(this.m_wheelNode.eulerAngles.z + deltaAngle);
171	        this.m_wheelNode.setRotationFromEuler(0, 0, next);
172	    }
173	    //#endregion 生命週期
174	
175	    //#region 事件註冊
176	    private RegisterEvent() {
177	        if (this.m_isEventRegistered) {
178	            return;
179	        }
180	        this.m_isEventRegistered = true;
181	        this.EVENT_LIST.forEach(event => eventManager.Register(event, this));
182	    }
183	
184	    private UnregisterEvent() {
185	        if (!this.m_isEventRegistered) {
186	            return;
187	        }
188	        this.EVENT_LIST.forEach(event => eventManager.UnRegister(event, this));
189	        this.m_isEventRegistered = false;
190	    }
191	
192	    /**
193	     * @ch 事件分派
194	     */
195	    OnEvent(event: string, ...args: any[]) {
196	        switch (event) {
197	            case FEATURE_WHEEL_EVENT.INIT:
198	                if (args.length > 0 && typeof args[0] === 'object' && args[0] !== null) {
199	                    this.Init(args[0]);
200	                } else {
201	                    error('FeatureWheel INIT 參數無效');
202	                }
203	                break;
204	
205	            case FEATURE_WHEEL_EVENT.SET_WHEEL_DATA:
206	                if (args.length > 0 && Array.isArray(args[0])) {
207	                    this.SetWheelData(args[0]);
208	                } else {
209	                    error('FeatureWheel SET_WHEEL_DATA 參數無效');
210	                }
211	                break;
212	
213	            case FEATURE_WHEEL_EVENT.PLAY_SPIN:
214	                if (args.length > 0 && typeof args[0] === 'number') {
215	                    this.PlaySpin(args[0], typeof args[1] === 'function' ? args[1] : undefined);
216	                } else {
217	                    error('FeatureWheel PLAY_SPIN 參數無效');
218	                }
219	                break;
220	
221	            case FEATURE_WHEEL_EVENT.SHOW_UI:
222	                this.SetUIShow(true);
223	                break;
224	
225	            case FEATURE_WHEEL_EVENT.HIDE_UI:
226	                this.SetUIShow(false);
227	                break;
228	
229	            case FEATURE_WHEEL_EVENT.RESUME_IDLE:
230	                this.ResumeIdle();
231	                break;
232	
233	            case FEATURE_WHEEL_EVENT.HIDE_RESULT:
234	                this.HideResult();
235	                break;
236	        }
237	    }
238	    //#endregion 事件註冊
239	
240	    //#region 方法
241	    /**
242	     * @ch 初始化（IF-1）
243	     */
244	    private Init(gameView: GameView) {
245	        this.m_gameView = gameView;
246	        this.m_isInit = true;
247	    }
248	
249	    /**
250	     * @ch 設置 12 格資料並更新 icon（IF-2 / BC-5 / EH-2）
251	     * @param segments server 給的 12 格資料
252	     */
253	    private SetWheelData(segments: SegmentDescriptor[]) {
254	        // BC-9 行為約束：轉動中拒絕換資料，避免落點與顯示不一致
255	        if (this.m_isSpinning) {
256	            warn('FeatureWheel SetWheelData 轉動中，拒絕本次設置');
257	            return;
258	        }
259	        if (!segments) {
260	            warn('FeatureWheel SetWheelData 資料為空');
261	            return;
262	        }
263	
264	        // EH-2：長度 > 12 取前 12
265	        if (segments.length > FEATURE_WHEEL_SEGMENT_COUNT) {
266	            warn(`FeatureWheel SetWheelData 長度 ${segments.length} > ${FEATURE_WHEEL_SEGMENT_COUNT}，取前 ${FEATURE_WHEEL_SEGMENT_COUNT} 格`);
267	        }
268	        this.m_segments = segments.slice(0, FEATURE_WHEEL_SEGMENT_COUNT);
269	
270	        // EH-2：長度 < 12 → 渲染已提供格，其餘格保持預設
271	        if (this.m_segments.length < FEATURE_WHEEL_SEGMENT_COUNT) {
272	            warn(`FeatureWheel SetWheelData 長度 ${this.m_segments.length} < ${FEATURE_WHEEL_SEGMENT_COUNT}，其餘格保持預設`);
273	        }
274	
275	        this.BindSegmentIcons();
276	
277	        this.m_isIdle = true;
278	    }
279	
280	    /**
281	     * @ch 依當前資料綁定各格 icon（BC-4 / EH-2）
282	     * None / 無資料格 → 清空不顯示；其餘依 type 換圖。倍率值已移除，Label 一律清空防殘留。
283	     * FS_BG 底圖：僅該格 type 為 FreeGame 時開啟（作底凸顯免費遊戲符號）；其餘格關閉以保冪等（R-2）。
284	     */
285	    private BindSegmentIcons() {
286	        // 迭代固定 12 格確保冪等（R-2）：二次設定變少時，超出資料的格重置為預設，不殘留舊值
287	        for (let i = 0; i < FEATURE_WHEEL_SEGMENT_COUNT; i++) {
288	            const seg = i < this.m_segments.length ? this.m_segments[i] : null;
289	
290	            // 換 icon：None / 無資料格 → 清空（暫不顯示）；其餘依 type 換圖（BC-4）
291	            const spriteChange = this.m_segmentSpriteChanges[i];
292	            if (spriteChange) {
293	                if (!seg || seg.type === FeatureWheelSegmentType.None) {
294	                    spriteChange.ClearSprite();
295	                } else {
296	                    spriteChange.ChangeSpriteByIndex(TypeToIconIndex(seg.type));
297	                }
298	
299	                // FS_BG 底圖：與 icon 同生命週期，從同格 item root 取子節點（無資料/非 FreeGame 一律關，保冪等）
300	                const fsBg = spriteChange.node?.getChildByName('FS_BG');
301	                if (fsBg) {
302	                    fsBg.active = !!seg && seg.type === FeatureWheelSegmentType.FreeGame;
303	                }
304	            }
305	
306	            // 倍率值已移除：清空 Label，避免殘留設計期/前一次的文字
307	            const label = this.m_segmentValueLabels[i];
308	            if (label) {
309	                label.string = '';
310	            }
311	        }
312	    }
313	
314	    /**
315	     * @ch 轉動並落在指定格（IF-3 / BC-3 / BC-6 / BC-7 / BC-8 / BC-9 / EH-1 / EH-3）
316	     * 守衛順序（DR-10）：① 轉動中重入 → ② 未初始化/無資料 → ③ landIndex 範圍
317	     * 完成訊號鏈（DR-2 / BC-7）：await 轉動 → await 落點演出 → callback → 最後釋放 m_isSpinning
318	     * @param landIndex 落點格索引 (0~11)
319	     * @param callback 完成回調，帶選中格 {index, type, value}
320	     */
321	    private async PlaySpin(landIndex: number, callback?: (result: SpinResult) => void) {
322	        // ① BC-9 轉動中重入 → 忽略
323	        if (this.m_isSpinning) {
324	            warn('FeatureWheel PlaySpin 轉動中，忽略本次請求');
325	            return;
326	        }
327	        // ② EH-3 未初始化或無資料
328	        if (!this.m_isInit || this.m_segments.length === 0) {
329	            warn('FeatureWheel PlaySpin 未初始化或尚未設置輪盤資料');
330	            return;
331	        }
332	        // ③ EH-1 landIndex 範圍
333	        if (landIndex < 0 || landIndex >= FEATURE_WHEEL_SEGMENT_COUNT) {
334	            warn(`FeatureWheel PlaySpin landIndex ${landIndex} 超出範圍 0~${FEATURE_WHEEL_SEGMENT_COUNT - 1}`);
335	            return;
336	        }
337	
338	        this.m_isSpinning = true;
339	        // 轉動開始即關閉 Idle：轉完「不」自動恢復；待盤面其他表演結束由 RESUME_IDLE 手動恢復
340	        this.m_isIdle = false;
341	        try {
342	            await this.RotateToIndex(landIndex);     // BC-3 / BC-6
343	            await this.PlayLandAnnounce(landIndex);  // BC-7
344	            const seg = this.m_segments[landIndex];
345	            // callback 包獨立 try（R-1）：呼叫端 callback 自身例外不被遮蔽成「轉動失敗」
346	            try {
347	                callback?.({ index: landIndex, type: seg.type });
348	            } catch (cbErr) {
349	                error('FeatureWheel PlaySpin callback 執行失敗: ' + cbErr);
350	            }
351	        } catch (e) {
352	            error('FeatureWheel PlaySpin 轉動/演出失敗: ' + e);
353	        } finally {
354	            // BC-7：釋放點在 callback 之後，避免演出/回呼期間被重入
355	            this.m_isSpinning = false;
356	        }
357	    }
358	
359	    /**
360	     * @ch 旋轉到 landIndex，停在頂端指針（BC-3 / BC-6）
361	     * 角度計算用 ComputeTargetAngle（依 m_clockwise 單向單調，不沿用會反向的 angleDiff）
362	     */
363	    private RotateToIndex(landIndex: number): Promise<void> {
364	        return new Promise<void>((resolve) => {
365	            if (!this.m_wheelNode || !this.m_wheelNode.isValid) {
366	                resolve();
367	                return;
368	            }
369	            const currentAngle = this.m_wheelNode.eulerAngles.z;
370	            const targetAngle = ComputeTargetAngle(landIndex, currentAngle, this.m_clockwise);
371	            const anim = { angle: currentAngle };
372	            tween(anim)
373	                .to(FeatureWheelManager.ROTATE_TIME, { angle: targetAngle }, {
374	                    easing: 'cubicOut',
375	                    onUpdate: () => {
376	                        if (this.m_wheelNode?.isValid) {
377	                            this.m_wheelNode.setRotationFromEuler(0, 0, anim.angle);
378	                        }
379	                    },
380	                })
381	                .call(() => {
382	                    // DR-9：轉動結束後正規化角度，防 BC-8 連續轉動累積漂移
383	                    if (this.m_wheelNode?.isValid) {
384	                        this.m_wheelNode.setRotationFromEuler(0, 0, NormalizeAngle(targetAngle));
385	                    }
386	                    resolve();
387	                })
388	                .start();
389	        });
390	    }
391	
392	    /**
393	     * @ch 落點演出（暫代）：用結果展示牌秀出落點 feature 符號，秀出即 resolve（不等退場）
394	     * ⚠️ BC-7 語意調整（暫代）：原「演出完成才 resolve」改為「秀出展示牌即 resolve」；
395	     *    展示牌停留至呼叫端 dispatch HIDE_RESULT 才退場（PlaySpin 完成後 m_isSpinning 會在展示牌仍顯示時釋放）
396	     * 符號索引複用 BindSegmentIcons 同套 TypeToIconIndex（None → 清空）
397	     */
398	    private PlayLandAnnounce(landIndex: number): Promise<void> {
399	        return new Promise<void>((resolve) => {
400	            const seg = this.m_segments[landIndex];
401	            if (!seg || !this.m_resultNode || !this.m_resultNode.isValid) {
402	                resolve();
403	                return;
404	            }
405	            // 符號與背景同步切換（同套 TypeToIconIndex；None → 清空）
406	            this.ApplyResultSprite(this.m_resultSpriteChange, seg.type);
407	            this.ApplyResultSprite(this.m_resultBgSpriteChange, seg.type);
408	            this.m_resultNode.active = true;
409	            resolve();
410	        });
411	    }
412	
413	    /**
414	     * @ch 套用落點 type 對應圖到指定 SpriteChange（None → 清空；其餘依 TypeToIconIndex 換圖）
415	     * 給結果展示牌的符號與背景共用，確保兩者索引邏輯一致
416	     */
417	    private ApplyResultSprite(spriteChange: SpriteChange | null, type: FeatureWheelSegmentType) {
418	        if (!spriteChange) {
419	            return;
420	        }
421	        if (type === FeatureWheelSegmentType.None) {
422	            spriteChange.ClearSprite();
423	        } else {
424	            spriteChange.ChangeSpriteByIndex(TypeToIconIndex(type));
425	        }
426	    }
427	
428	    /**
429	     * @ch 隱藏結果展示牌（HIDE_RESULT 退場；暫代落點演出的收場）
430	     */
431	    private HideResult() {
432	        if (this.m_resultNode && this.m_resultNode.isValid) {
433	            this.m_resultNode.active = false;
434	        }
435	    }
436	
437	    /**
438	     * @ch 顯示/隱藏 UI（IF-4）
439	     */
440	    private SetUIShow(isShow: boolean) {
441	        if (this.m_rootNode) {
442	            this.m_rootNode.active = isShow;
443	        }
444	        // 隱藏 UI 時一併收掉結果展示牌，避免下次顯示殘留上一輪落點符號
445	        if (!isShow) {
446	            this.HideResult();
447	        }
448	        // Idle：顯示時開始緩轉、隱藏時停止（PlaySpin 後不自動恢復，須由 RESUME_IDLE 手動恢復）
449	        this.m_isIdle = isShow;
450	    }
451	
452	    /**
453	     * @ch 手動恢復 Idle 緩轉（IF）
454	     * 用途：PlaySpin 後輪盤停住，呼叫端在盤面其他表演結束後觸發此方法才續轉
455	     * 注意：若仍在轉動中，由 update 的 m_isSpinning 守衛延後至轉完才實際緩轉
456	     */
457	    private ResumeIdle() {
458	        this.m_isIdle = true;
459	    }
460	
461	    /**
462	     * @ch dev-only 設定斷言（DR-3/DR-12 緩解：驗節點數量，順序語意仍須人工核對 prefab）
463	     */
464	    private DevAssertConfig() {
465	        if (!DEV) {
466	            return;
467	        }
468	        if (this.m_segmentSpriteChanges.length !== FEATURE_WHEEL_SEGMENT_COUNT) {
469	            warn(`FeatureWheel 設定異常：SpriteChange 數 ${this.m_segmentSpriteChanges.length} ≠ ${FEATURE_WHEEL_SEGMENT_COUNT}`);
470	        }
471	        if (this.m_segmentNodes.length !== FEATURE_WHEEL_SEGMENT_COUNT) {
472	            warn(`FeatureWheel 設定異常：落點節點數 ${this.m_segmentNodes.length} ≠ ${FEATURE_WHEEL_SEGMENT_COUNT}`);
473	        }
474	    }
475	    //#endregion 方法
476	
477	    //#region 測試功能
478	    /**@ch 測試用：當前轉動落點索引（每次轉動 +1 循環 0~11）*/
479	    private m_testLandIndex = 0;
480	    /**@ch 測試用：當前 UI 顯示狀態（給 DIGIT_4 切換）*/
481	    private m_testUIShown = false;
482	
483	    /**
484	     * @ch 註冊測試按鍵（僅 DEBUG 構建生效；正式構建零副作用）
485	     */
486	    private RegisterTestKeyCodes() {
487	        if (!DEBUG) {
488	            return;
489	        }
490	        // input.on(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
491	    }
492	
493	    /**
494	     * @ch 取消註冊測試按鍵（與 RegisterTestKeyCodes 對稱，避免監聽洩漏）
495	     */
496	    private UnregisterTestKeyCodes() {
497	        if (!DEBUG) {
498	            return;
499	        }
500	        // input.off(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
501	    }
502	
503	    /**
504	     * @ch 檢查測試按鍵，走真實 eventManager 事件路徑驗證 FeatureWheel 功能
505	     * DIGIT_1：初始化 + 設定預設輪盤資料 + 顯示 UI（一鍵就緒）
506	     * DIGIT_2：轉動到下一格（循環 0~11）並印出落點結果（驗證旋轉/落點演出/callback）
507	     * DIGIT_3：重設隨機輪盤資料（驗證 icon 與乘倍數值動態更新）
508	     * DIGIT_4：切換顯示/隱藏 UI
509	     */
510	    private CheckTestKeyCode(event: EventKeyboard) {
511	        switch (event.keyCode) {
512	            // case KeyCode.DIGIT_1:
513	            //     log('[FeatureWheel 測試] 初始化 + 設定預設資料 + 顯示 UI');
514	            //     // INIT 僅需非 null 物件以通過參數驗證並翻起 m_isInit；
515	            //     // m_gameView 在本元件未被讀取，測試以 this.node 佔位即可
516	            //     eventManager.Dispatch(FEATURE_WHEEL_EVENT.INIT, this.node);
517	            //     eventManager.Dispatch(FEATURE_WHEEL_EVENT.SET_WHEEL_DATA, GetDefaultSegments());
518	            //     eventManager.Dispatch(FEATURE_WHEEL_EVENT.SHOW_UI);
519	            //     break;
520	
521	            case KeyCode.DIGIT_2: {
522	                const landIndex = this.m_testLandIndex % FEATURE_WHEEL_SEGMENT_COUNT;
523	                this.m_testLandIndex++;
524	                log(`[FeatureWheel 測試] 轉動到第 ${landIndex} 格`);
525	                eventManager.Dispatch(FEATURE_WHEEL_EVENT.PLAY_SPIN, landIndex, (result: SpinResult) => {
526	                    log(`[FeatureWheel 測試] 落點結果 index=${result.index} type=${result.type}`);
527	                });
528	                break;
529	            }
530	            
531	            case KeyCode.DIGIT_3:
532	                log('[FeatureWheel 測試] 恢復 Idle 緩轉');
533	                eventManager.Dispatch(FEATURE_WHEEL_EVENT.HIDE_RESULT);
534	                eventManager.Dispatch( FEATURE_WHEEL_EVENT.RESUME_IDLE );
535	                break;
536	
537	            case KeyCode.DIGIT_4:
538	                this.m_testUIShown = !this.m_testUIShown;
539	                log(`[FeatureWheel 測試] 切換 UI 顯示 → ${this.m_testUIShown}`);
540	                eventManager.Dispatch(this.m_testUIShown ? FEATURE_WHEEL_EVENT.SHOW_UI : FEATURE_WHEEL_EVENT.HIDE_UI);
541	                break;
542	        }
543	    }
544	
545	    /**
546	     * @ch 產生 12 格隨機測試資料（type 隨機）
547	     */
548	    private BuildRandomTestSegments(): SegmentDescriptor[] {
549	        const types = [
550	            FeatureWheelSegmentType.SymbolConvert,
551	            FeatureWheelSegmentType.Multiplier,
552	            FeatureWheelSegmentType.Upgrade,
553	            FeatureWheelSegmentType.GrandJP,
554	            FeatureWheelSegmentType.FreeGame,
555	        ];
556	        const segments: SegmentDescriptor[] = [];
557	        for (let i = 0; i < FEATURE_WHEEL_SEGMENT_COUNT; i++) {
558	            const type = types[Math.floor(Math.random() * types.length)];
559	            segments.push({ type });
560	        }
561	        return segments;
562	    }
563	    //#endregion 測試功能
564	}
