1	import { _decorator, log } from "cc";
2	import GameView from "../GameView";
3	import { BaseState, eventManager, stateManager } from "db://astarte-framework/Managers";
4	import { Define } from "db://astarte-framework/utilis";
5	import Game_Define from "../Game_Define";
6	import { FEATURE_WHEEL_EVENT } from "../FeatureWheel/FeatureWheelManager";
7	import { FeatureWheelSegmentType, FEATURE_WHEEL_SEGMENT_COUNT, SpinResult } from "../FeatureWheel/FeatureWheelTypes";
8	import { FEATURE_MARK_EVENT } from "../FeatureWheel/FeatureMarkEvent";
9	import { JP_EVENT, JP_Type } from "../JP/JP_Define";
10	import { ar2es2Proto } from "@igs-arcade-division-rd2/uk_872_eyestrike2_proto";
11	
12	const { ccclass } = _decorator;
13	
14	/**
15	 * @ch Feature Wheel 轉輪演出 State（骨架 + 轉輪，不含落點後盤面效果）
16	 *
17	 * 位置：plate0 的 AWARD（對線獎）之後、ROUND_SHOW_END 之前（由 GameView.AfterShowWin 守衛導向）。
18	 * 對應規格 3.1 STEP3-5「檢查轉輪 → 觸發轉輪 → 第一次發動」；重轉（STEP6）仍為後續 plate。
19	 *
20	 * 職責邊界（scope = 骨架+轉輪演出）：
21	 *   IN  — SHOW_UI → 依 WheelFeatures 逐項 PLAY_SPIN(SlotIndex) 序列等待 → HIDE_UI → ROUND_SHOW_END
22	 *   OUT — 落點後的盤面演出（符號轉 CASH / 乘倍 badge / 升級 / FG 交棒）由後續 plate 停輪或後續階段處理
23	 *
24	 * 不在此 State 改動狀態機路由：FG（Type=0/4）的實際進場仍走既有 CheckState/LeaveRespin 的 IsGoingToFree。
25	 */
26	@ccclass( "FeatureWheelShowState" )
27	export class FeatureWheelShowState extends BaseState
28	{
29	    /**
30	     * @ch 暫代 dwell（秒）：fly/mark 動畫尚未上線，非 GrandJP 落點展示牌會同幀閃掉看不到，
31	     * 故 HIDE_RESULT 前臨時停留一段。TODO(暫代)：PlayFlyEffect 實作真實耗時動畫後移除。
32	     */
33	    private static readonly RESULT_DWELL_SEC = 0.8;
34	
35	    private m_gameView: GameView = null;
36	
37	    constructor( gameView: GameView )
38	    {
39	        super();
40	        this.m_gameView = gameView;
41	    }
42	
43	    public async OnEnter()
44	    {
45	        log( "OnEnter State : FEATURE_WHEEL_SHOW" );
46	
47	        // 只取「有效」轉輪項（Type≠None）。理論上進到此 State 必有 ≥1（AfterShowWin 已用 HasActiveWheel 守衛），
48	        // 此處再過濾一次防禦：把混在其中的 None 項剔除，避免無意義轉動。
49	        const features = ( this.m_gameView.RoundInfo?.WheelFeatures ?? [] )
50	            .filter( w => w != null && w.Type !== FeatureWheelSegmentType.None );
51	
52	        if ( features.length === 0 )
53	        {
54	            // 不應發生（守衛已擋）；fail-loud 但不炸狀態機，直接續流程
55	            console.warn( "[FeatureWheelShowState] 無有效 WheelFeatures，跳過轉輪演出" );
56	            stateManager.NextState( Game_Define.GameState.ROUND_SHOW_END );
57	            return;
58	        }
59	
60	        // eventManager.Dispatch( FEATURE_WHEEL_EVENT.SHOW_UI );
61	
62	        // WheelCount 迴圈：逐項「序列等待」——PlaySpin 有 m_isSpinning 重入守衛，
63	        // 未等前一次 callback 就發下一次會被靜默丟棄（FeatureWheelManager 行為，BC-2 硬約束）。
64	        for ( const wf of features )
65	        {
66	            const landIndex = wf.SlotIndex ?? 0;
67	
68	            // 防 hang：PlaySpin 對越界 landIndex 是 warn+return（不呼叫 callback）→ 若 await 會永久掛住。
69	            // 故在 dispatch 前先驗範圍，越界則 fail-loud 跳過該次（不 await）。
70	            if ( landIndex < 0 || landIndex >= FEATURE_WHEEL_SEGMENT_COUNT )
71	            {
72	                console.warn( `[FeatureWheelShowState] SlotIndex=${landIndex} 越界 0~${FEATURE_WHEEL_SEGMENT_COUNT - 1}，跳過該次轉動` );
73	                continue;
74	            }
75	
76	            const result = await this.PlaySpinOnce( landIndex );
77	
78	            // fail-loud 一致性：落點 type 應與 server WheelFeatures.Type 相符
79	            // （前提 P：server SlotIndex 與客戶端 12 格序一致——待 server 對拍；不符僅 warn 不阻流程）
80	            if ( result != null && result.type !== wf.Type )
81	            {
82	                console.warn( `[FeatureWheelShowState] 落點 type 不一致：landed=${result.type} vs server=${wf.Type}（SlotIndex=${landIndex}）` );
83	            }
84	
85	            // 飛個效果下來到盤面指定位置
86	            await this.PlayFlyEffect( wf );
87	
88	            // ②標記 seam：通知演出端在盤面標記此功能（標記/icon/乘倍/Grand報獎/FreeGame盤外 由同事 handler 渲染）。
89	            await this.PlayMarkEffect( wf );
90	
91	            // TODO(暫代)：fly/mark 動畫上線前，臨時停留讓展示牌可見；之後移除此 dwell。
92	            await Define.Wait( this.m_gameView, FeatureWheelShowState.RESULT_DWELL_SEC );
93	
94	            eventManager.Dispatch( FEATURE_WHEEL_EVENT.HIDE_RESULT );
95	        }
96	
97	        // ③轉換 seam：標記後、進 respin 前，套用符號轉換（一般符號→CASH）。fire-and-forget；演出由同事 handler 渲染。
98	        const transferResult = this.m_gameView.RoundInfo?.TransferResult ?? [];
99	        if ( transferResult.length > 0 )
100	        {
101	            await this.PlaySymbolTransferEffect( transferResult );
102	        }
103	
104	        eventManager.Dispatch( FEATURE_WHEEL_EVENT.RESUME_IDLE );
105	
106	        stateManager.NextState( Game_Define.GameState.ROUND_SHOW_END );
107	    }
108	
109	    /**
110	     * @ch 包一層 Promise 等單次 PLAY_SPIN 完成回調
111	     * @param landIndex 落點格索引（已由呼叫端確認 0~11 範圍）
112	     */
113	    private PlaySpinOnce( landIndex: number ): Promise<SpinResult | null>
114	    {
115	        return new Promise<SpinResult | null>( resolve =>
116	        {
117	            eventManager.Dispatch(
118	                FEATURE_WHEEL_EVENT.PLAY_SPIN,
119	                landIndex,
120	                ( result: SpinResult ) => resolve( result ?? null )
121	            );
122	        } );
123	    }
124	
125	    public OnProcess()
126	    {
127	
128	    }
129	
130	    public OnLeave()
131	    {
132	
133	    }
134	
135	    /**
136	     * @ch 播放飛行效果
137	     * @param data 飛行效果資料
138	     */
139	    private async PlayFlyEffect( data: ar2es2Proto.IFeatureResult )
140	    {
141	        // TODO: 飛個效果下來到盤面指定位置
142	        log( "PlayFlyEffect data: " + JSON.stringify( data ) );
143	    }
144	
145	    /**
146	     * @ch 播放標記效果
147	     * @param data 標記效果資料
148	     */
149	    private async PlayMarkEffect( data: ar2es2Proto.IFeatureResult )
150	    {
151	        log( "PlayMarkEffect data: " + JSON.stringify( data ) );
152	
153	        // 轉到 GRAND JP：不播標配標記，直接播 JP 報獎（JP_Manager 已實作，await 等報獎演完再續迴圈）。
154	        if ( data.Type === FeatureWheelSegmentType.GrandJP )
155	        {
156	            await new Promise<void>( resolve =>
157	            {
158	                eventManager.Dispatch( JP_EVENT.PLAY_SHOW_AWARD, JP_Type.GRAND, () => resolve() );
159	            } );
160	            return;
161	        }
162	
163	        await new Promise<void>( resolve =>
164	        {
165	            eventManager.Dispatch( FEATURE_MARK_EVENT.SHOW_MARK, data.Type, data.Positions ?? [], data.Multipliers ?? [], () => resolve() );
166	        } );
167	    }
168	
169	    /**
170	     * @ch 播放符號轉換效果
171	     * @param data 符號轉換效果資料
172	     */
173	    private async PlaySymbolTransferEffect( data: ar2es2Proto.ITransformInfo[] )
174	    {
175	        await new Promise<void>( resolve =>
176	        {
177	            eventManager.Dispatch( FEATURE_MARK_EVENT.APPLY_TRANSFER, data, () => resolve() );
178	        } );
179	    }
180	}
