let info: protocol.ar2es2Proto.IGameInfoData = protocol.ar2es2Proto.GameInfoData.decode( data );
log("OnCommand Define.AckType.info", info);

this.GoldBlitzRouletteWheelData = info.WheelData;

this.SetTxt();
this.SettingBottomBar();

/**@ch 初始化JP*/
eventManager.Dispatch( JP_EVENT.INIT, info.JPOdds );

/**@ch 初始化魔法罐*/
eventManager.Dispatch( MAGIC_POT_EVENT.INIT, this, info.ScAccuStage );

/**@ch 初始化倍率*/
//eventManager.Dispatch( MULTIPLIER_EVENT.INIT, this, info.MultiplierIndex );

/**@ch 初始化輪盤*/
eventManager.Dispatch( FEATURE_WHEEL_EVENT.INIT, this );

// 載入時設主遊戲(MG)層；FG 進/離場由 SetFeatureWheelLayer 切 FreeGame/MainGame（Enter/LeaveFreeState）
eventManager.Dispatch( FEATURE_WHEEL_EVENT.SET_WHEEL_DATA, ParseServerWheelData( info.WheelData, WheelDataLayer.MainGame ) );

newBottombarManager.AutoPlayPanelInit();
newExtraManager.FeaturesInit(
    ["Img/features/left/spriteFrame", "Img/features/right/spriteFrame"], // 設定Demo畫面的圖片
    [Game_Define.StringKey.MC_FEATURES_LEFT, Game_Define.StringKey.MC_FEATURES_RIGHT], // 設定Demo畫面的文字圖
    Game_Define.SPICY_LEVEL, // 設定Demo畫面的辣椒數
    this.m_titleSpriteAtlas // 設定Demo畫面的標題圖
);
let atlas: SpriteAtlas = localeStringManager.GetGameAtlas();
newExtraManager.SetFeatruesDesc([atlas.getSpriteFrame("txt1"), atlas.getSpriteFrame("txt2")]);
newExtraManager.CheckFirstFeatures();

