    private PlayAnimation( spine: sp.Skeleton, animName: string, isLoop: boolean = false, track: number = 0 ): Promise<boolean>
    {
        return new Promise<boolean>(
            resolve =>
            {
                let isCancel = false;
                this.m_cancelCb = () =>
                {
                    isCancel = true;
                    resolve( isCancel );
                };
                spine.clearTrack( track );
                spine.setToSetupPose();
                let trackEntry: sp.spine.TrackEntry = spine.setAnimation( track, animName, isLoop );
                let completeCb = () =>
                {
                    this.m_cancelCb = null;
                    resolve( isCancel );
                };

                if ( trackEntry )
                {
                    spine.setTrackEventListener( trackEntry, ( trackEntry, event: sp.spine.Event ) =>
                    {
                        let name = event.data.name;
                        let strValue = event.stringValue;
                        this.m_eventCb && this.m_eventCb( name, strValue, animName );
                    } );
                    spine.setTrackCompleteListener( trackEntry, () =>
                    {
