    SegmentDescriptor,
    SpinResult,
    FeatureWheelSegmentType,
    FEATURE_WHEEL_SEGMENT_COUNT,
    TypeToIconIndex,
    TypeToSkin,
    BIG_WHEEL_DEFAULT_SKIN,
    ComputeTargetAngle,
    NormalizeAngle,
    GetDefaultSegments,
} from './FeatureWheelTypes';

