/**
 * @ch 播放震動效果
 * @param callback 完成後回調
 * @param delay 延遲時間
 * @returns Promise 震動效果完成的 Promise
 */
private async PlayShakeEffect(callback?: () => void, delay: number = 0): Promise<void> {
    if (!this.m_shakeComponent) {
        callback?.();
        return Promise.resolve();
    }

    await Define.Wait(this, delay);
    this.m_shakeComponent.shake();
    await Define.Wait(this, this.m_shakeComponent.Duration);
    callback?.();
}

/**
 * @ch 播放進場動畫
 * @param callback 完成後回調
 * @returns Promise 動畫完成的 Promise
 */
private async PlayInAnim(callback?: () => void): Promise<void>
{
    return new Promise<void>((resolve) => {
        // 在 try 外部宣告，以便在 catch 中使用
        let targetPosition: Vec3 = null;
        let targetScale: Vec3 = null;

        try {
            // 安全檢查
            if (!this.m_rootNode) {
                error("[ReelManager] m_rootNode is null, cannot play in animation");
                callback?.();
                resolve();
                return;
            }

            // 目標位置 (使用 clone 避免引用問題)
            targetPosition = this.m_isMovedReel ? this.m_originalPosition.clone() : this.m_rootNode.position.clone();

            // 先移動位置
            if (!this.m_isMovedReel) {
                this.m_rootNode.setPosition(
                    targetPosition.x,
                    targetPosition.y + ReelManager.PLAY_IN_ANIM_POSITION_Y,
                    targetPosition.z
                );
                this.m_isMovedReel = true;
            }

            // 目標縮放 (使用 clone 避免引用問題)
            targetScale = this.m_rootNode.scale.clone();

            // 先放大
            this.m_rootNode.setScale(
                ReelManager.PLAY_IN_ANIM_SCALE,
                ReelManager.PLAY_IN_ANIM_SCALE,
                1
            );

            // 動畫 (同時進行縮放和移動，使用 cubicOut 緩動實現快到慢效果)
            tween(this.m_rootNode)
                .parallel(
                    tween<Node>().to(ReelManager.PLAY_IN_ANIM_DURATION, { position: targetPosition }, { easing: easing.cubicOut }),
                    tween<Node>().to(ReelManager.PLAY_IN_ANIM_DURATION, { scale: targetScale }, { easing: easing.cubicOut })
                )
                .call(() => {
                    callback?.();

                    // 重置移動過轉輪
                    this.m_isMovedReel = false;

                    resolve();
                })
                .start();
        } catch (err) {
            error('[ReelManager] PlayInAnim error:', err);

            // 還原位置和縮放到目標狀態
            if (this.m_rootNode && targetPosition && targetScale) {
                this.m_rootNode.setPosition(targetPosition);
                this.m_rootNode.setScale(targetScale);
            }

            // 即使發生錯誤也要執行 callback，確保流程不會卡住
            callback?.();
            // 重置移動過轉輪
            this.m_isMovedReel = false;
            resolve();
        }
    });
}

/**
 * @ch 取得要縮放的目標節點
