private GetZoomTarget(): Node {
    if (this.m_zoomTargetNode) return this.m_zoomTargetNode;

    // 若未指定，嘗試往上找 GameView 節點 (通常包含背景與轉輪)
    let current = this.node;
    while (current) {
        if (current.name === "GameView" || current.getComponent("GameView")) {
            return current;
        }
        current = current.parent;
    }

    // 退而求其次使用 m_rootNode 的父節點或 m_rootNode
    if (this.m_rootNode && this.m_rootNode.parent) return this.m_rootNode.parent;
    return this.m_rootNode || this.node;
}

