private ZoomInReel(targetLocalPos: Vec3, scale: number, duration: number | (() => void) = 0.5, callback?: () => void) {
    const targetNode = this.GetZoomTarget();
    if (!targetNode) {
        error("[ReelManager] Zoom target is null, cannot zoom in");
        if (typeof duration === 'function') duration();
        else callback?.();
        return;
    }

    let actualDuration = typeof duration === 'number' ? duration : 0.5;
    let actualCallback = typeof duration === 'function' ? duration : callback;

    Tween.stopAllByTarget(targetNode);

    if (!this.m_isZoomed) {
        this.m_zoomOriginalPosition.set(targetNode.position);
        this.m_zoomOriginalScale.set(targetNode.scale);
        this.m_isZoomed = true;
    }

    const targetPos = new Vec3(
        this.m_zoomOriginalPosition.x - targetLocalPos.x * scale,
        this.m_zoomOriginalPosition.y - targetLocalPos.y * scale,
        this.m_zoomOriginalPosition.z
    );
    const targetScaleObj = new Vec3(scale, scale, 1);

    tween(targetNode)
        .parallel(
            tween<Node>().to(actualDuration, { position: targetPos }, { easing: easing.cubicOut }),
            tween<Node>().to(actualDuration, { scale: targetScaleObj }, { easing: easing.cubicOut })
        )
        .call(() => {
            actualCallback?.();
        })
        .start();
}

/**
 * @ch 還原鏡頭縮放與位置
 * @param duration 動畫時長
 * @param callback 完成回調
 */
private RestoreZoom(duration: number | (() => void) = 0.5, callback?: () => void) {
    let actualDuration = typeof duration === 'number' ? duration : 0.5;
    let actualCallback = typeof duration === 'function' ? duration : callback;

    const targetNode = this.GetZoomTarget();
    if (!targetNode || !this.m_isZoomed) {
        actualCallback?.();
        return;
    }

    Tween.stopAllByTarget(targetNode);

    tween(targetNode)
        .parallel(
            tween<Node>().to(actualDuration, { position: this.m_zoomOriginalPosition }, { easing: easing.cubicOut }),
            tween<Node>().to(actualDuration, { scale: this.m_zoomOriginalScale }, { easing: easing.cubicOut })
        )
        .call(() => {
            this.m_isZoomed = false;
            actualCallback?.();
        })
        .start();
}
