            for ( const wf of features )
            {
            const landIndex = wf.SlotIndex ?? 0;

            // 防 hang：PlaySpin 對越界 landIndex 是 warn+return（不呼叫 callback）→ 若 await 會永久掛住。
            // 故在 dispatch 前先驗範圍，越界則 fail-loud 跳過該次（不 await）。
